import pytest
from urllib.parse import urlsplit

class TestPathUrl:
    def test_normal_case_with_path(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path/to/resource?query=1'})()
        assert obj.path_url() == "/path/to/resource?query=1"

    def test_normal_case_without_query(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path/to/resource'})()
        assert obj.path_url() == "/path/to/resource"

    def test_no_path(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com'})()
        assert obj.path_url() == "/"

    def test_empty_url(self):
        obj = type('TestObj', (object,), {'url': ''})()
        assert obj.path_url() == "/"

    def test_url_with_only_query(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com?query=1'})()
        assert obj.path_url() == "/?query=1"

    def test_url_with_fragment(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path#fragment'})()
        assert obj.path_url() == "/path"

    def test_url_with_encoded_characters(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path/to/resource?query=1&name=John%20Doe'})()
        assert obj.path_url() == "/path/to/resource?query=1&name=John%20Doe"

    def test_url_with_trailing_slash(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path/to/resource/'})()
        assert obj.path_url() == "/path/to/resource/"

    def test_url_with_multiple_query_parameters(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path?param1=value1&param2=value2'})()
        assert obj.path_url() == "/path?param1=value1&param2=value2"

    def test_url_with_special_characters_in_path(self):
        obj = type('TestObj', (object,), {'url': 'http://example.com/path/to/resource/!@#$%^&*()'})()
        assert obj.path_url() == "/path/to/resource/!@#$%^&*()"

    def test_invalid_url(self):
        obj = type('TestObj', (object,), {'url': 'invalid_url'})()
        with pytest.raises(ValueError):
            obj.path_url()

