    def test_prepare_cookies_sets_cookie_header(self, prepared_request):
        cookies_dict = {'session_id': 'abc123'}
        prepared_request.prepare_cookies(cookies_dict)
        assert "Cookie" in prepared_request.headers
        assert prepared_request.headers["Cookie"] == "session_id=abc123"

    def test_prepare_cookies_does_not_overwrite_header(self, prepared_request):
        cookies_dict = {'session_id': 'abc123'}
        prepared_request.headers["Cookie"] = "existing_cookie=value"
        prepared_request.prepare_cookies(cookies_dict)
        assert prepared_request.headers["Cookie"] == "existing_cookie=value"

    def test_prepare_cookies_empty_dict(self, prepared_request):
        cookies_dict = {}
        prepared_request.prepare_cookies(cookies_dict)
        assert "Cookie" not in prepared_request.headers

    def test_prepare_cookies_none(self, prepared_request):
        with pytest.raises(TypeError):
            prepared_request.prepare_cookies(None)

    def test_prepare_cookies_invalid_type(self, prepared_request):
        with pytest.raises(TypeError):
            prepared_request.prepare_cookies(123)

    def test_prepare_cookies_removes_cookie_header(self, prepared_request):
        cookies_dict = {'session_id': 'abc123'}
        prepared_request.prepare_cookies(cookies_dict)
        prepared_request.headers.pop("Cookie", None)
        prepared_request.prepare_cookies(cookies_dict)
        assert prepared_request.headers["Cookie"] == "session_id=abc123"

