import pytest

class MockResponse:
    def __init__(self, status_code, raw, content_consumed=False):
        self.status_code = status_code
        self.raw = raw
        self._content = False
        self._content_consumed = content_consumed

    def iter_content(self, chunk_size):
        return [b"chunk1", b"chunk2"] if self.raw else []

def test_content_normal_case():
    response = MockResponse(status_code=200, raw=True)
    assert response.content() == b"chunk1chunk2"

