import pytest

class MockResponse:
    def __init__(self, content, encoding=None, apparent_encoding=None):
        self.content = content
        self.encoding = encoding
        self.apparent_encoding = apparent_encoding

    def text(self):
        """Content of the response, in unicode."""
        content = None
        encoding = self.encoding

        if not self.content:
            return ""

        if self.encoding is None:
            encoding = self.apparent_encoding

        try:
            content = str(self.content, encoding, errors="replace")
        except (LookupError, TypeError):
            content = str(self.content, errors="replace")

        return content


def test_text_with_valid_utf8_content():
    response = MockResponse(b'Hello, World!', encoding='utf-8')
    assert response.text() == 'Hello, World!'


def test_text_with_valid_iso88591_content():
    response = MockResponse(b'Bonjour, le monde!', encoding='iso-8859-1')
    assert response.text() == 'Bonjour, le monde!'


def test_text_with_none_content():
    response = MockResponse(None)
    assert response.text() == ""


def test_text_with_empty_content():
    response = MockResponse(b'')
    assert response.text() == ""


def test_text_with_auto_detected_encoding():
    response = MockResponse(b'\xe2\x9c\x94', apparent_encoding='utf-8')
    assert response.text() == '✓'


def test_text_with_invalid_encoding():
    response = MockResponse(b'Hello, World!', encoding='invalid-encoding')
    assert response.text() == 'Hello, World!'  # Should fallback to replace


def test_text_with_type_error_on_encoding():
    response = MockResponse(b'Hello, World!', encoding=None)
    assert response.text() == 'Hello, World!'  # Should fallback to replace


def test_text_with_lookup_error_on_encoding():
    response = MockResponse(b'Hello, World!', encoding='unknown-encoding')
    assert response.text() == 'Hello, World!'  # Should fallback to replace


def test_text_with_bytes_content():
    response = MockResponse(b'\xe2\x9c\x94', encoding='utf-8')
    assert response.text() == '✓'


def test_text_with_non_bytes_content():
    response = MockResponse('Hello, World!', encoding='utf-8')
    assert response.text() == 'Hello, World!'  # Should handle str input correctly

