import pytest

class TestOrdinalNumber:
    def test_ordinal_number_one(self):
        assert self._ordinal_number(1) == "1வது"

    def test_ordinal_number_zero(self):
        assert self._ordinal_number(0) == "0ஆம்"

    def test_ordinal_number_positive(self):
        assert self._ordinal_number(5) == "5ஆம்"
        assert self._ordinal_number(10) == "10ஆம்"
        assert self._ordinal_number(100) == "100ஆம்"

    def test_ordinal_number_negative(self):
        assert self._ordinal_number(-1) == ""
        assert self._ordinal_number(-10) == ""
        assert self._ordinal_number(-100) == ""

    def test_ordinal_number_large_positive(self):
        assert self._ordinal_number(1000) == "1000ஆம்"
        assert self._ordinal_number(10000) == "10000ஆம்"

    def test_ordinal_number_large_negative(self):
        assert self._ordinal_number(-1000) == ""
        assert self._ordinal_number(-10000) == ""

    def test_ordinal_number_edge_cases(self):
        assert self._ordinal_number(2) == "2ஆம்"
        assert self._ordinal_number(3) == "3ஆம்"
        assert self._ordinal_number(4) == "4ஆம்"

