    def __init__(self):
        self.timeframes = {
            'hour': '{0} hour' if delta == 1 else '{0} hours',
            'minute': '{0} minute' if delta == 1 else '{0} minutes',
            'second': '{0} second' if delta == 1 else '{0} seconds',
            'day': {'dual': '{0} days', 'plural': '{0} days'},
        }

    def _format_timeframe(self, timeframe: str, delta: int) -> str:
        form = self.timeframes[timeframe]
        delta = abs(delta)
        if isinstance(form, Mapping):
            if delta == 2:
                form = form["dual"]
            else:
                form = form["plural"]

        return form.format(delta)

