import pytest
from collections import Mapping

# Assuming the class containing _format_timeframe is named TimeFrameFormatter
class TimeFrameFormatter:
    def __init__(self, timeframes):
        self.timeframes = timeframes

    def _format_timeframe(self, timeframe: str, delta: int) -> str:
        form = self.timeframes[timeframe]
        delta = abs(delta)
        if isinstance(form, Mapping):
            if delta == 2:
                form = form["2"]
            elif delta == 0 or 2 < delta <= 10:
                form = form["ten"]
            else:
                form = form["higher"]

        return form.format(delta)

# Sample timeframes for testing
timeframes = {
    'days': {
        "2": "2 days",
        "ten": "{} days",
        "higher": "{}+ days"
    },
    'weeks': {
        "2": "2 weeks",
        "ten": "{} weeks",
        "higher": "{}+ weeks"
    }
}

@pytest.fixture
def formatter():
    return TimeFrameFormatter(timeframes)

def test_format_timeframe_two_days(formatter):
    result = formatter._format_timeframe('days', 2)
    assert result == "2 days"

def test_format_timeframe_ten_days(formatter):
    result = formatter._format_timeframe('days', 10)
    assert result == "10 days"

def test_format_timeframe_zero_days(formatter):
    result = formatter._format_timeframe('days', 0)
    assert result == "0 days"

